102	            <Sparkles className="h-5 w-5" />
103	            <span className="font-poppins text-sm font-semibold">Manage Subscription</span>
104	          </Link>
105	        )}
106	
107	        <Separator className="bg-white/10 mb-4" />
108	
109	        <nav className="space-y-1">
110	          {menuItems.map((item) => {
111	            const Icon = item.icon;
112	            return (
113	              <Link
114	                key={item.path}
115	                to={item.path}
116	                onClick={onClose}
117	                className="flex items-center gap-3 px-4 py-3 rounded-lg text-white/80 hover:text-bronze hover:bg-white/5 transition-all"
118	              >
119	                <Icon className="h-5 w-5" />
120	                <span className="font-poppins text-sm font-medium">{item.label}</span>
121	              </Link>
122	            );
123	          })}
124	        </nav>
125	
126	        <Separator className="bg-white/10 my-4" />
127	
128	        <Button
129	          variant="ghost"
130	          onClick={handleSignOut}
131	          className="w-full justify-start gap-3 text-white/80 hover:text-red-400 hover:bg-white/5"
132	        >
133	          <LogOut className="h-5 w-5" />
134	          <span className="font-poppins text-sm font-medium">{t("profile.logout")}</span>
135	        </Button>
136	      </SheetContent>
137	    </Sheet>
138	  );
139	};
